import openpyxl
from openpyxl.chart.reference import Reference
import sys
import datetime

def get_month_rows(ws, target_month_str):
    """Find the start and end row for the given month in column A."""
    start_row = None
    end_row = None

    target_month_str = target_month_str.lower()

    # Check rows 2 to max
    for row in range(2, ws.max_row + 1):
        cell_val = ws.cell(row=row, column=1).value

        is_match = False
        if isinstance(cell_val, datetime.datetime):
            if cell_val.strftime('%b').lower() == target_month_str or cell_val.strftime('%B').lower() == target_month_str:
                is_match = True
        elif isinstance(cell_val, str):
            if target_month_str in cell_val.lower():
                is_match = True

        if is_match:
            if start_row is None:
                start_row = row
            end_row = row

    return start_row, end_row

def update_graphs(file_path, target_month):
    print(f"Loading {file_path} to update graphs for '{target_month}'...")
    try:
        wb = openpyxl.load_workbook(file_path)
    except Exception as e:
        print(f"Failed to load workbook: {e}")
        return

    sheets_of_interest = ['User_funnel', 'User Engagement', 'gameplay_report(score) ', 'gameplay_report(time) ']

    updated_any = False

    for sheet_name in sheets_of_interest:
        if sheet_name in wb.sheetnames:
            ws = wb[sheet_name]

            # Find the rows corresponding to the target month
            start_row, end_row = get_month_rows(ws, target_month)

            if start_row and end_row:
                print(f"Sheet '{sheet_name}': Found '{target_month}' data from row {start_row} to {end_row}.")

                if ws._charts:
                    for i, chart in enumerate(ws._charts):
                        # Assuming the chart plots data from Column B against Categories from Column A
                        # We will update the series to the new row range
                        for j, series in enumerate(chart.series):
                            try:
                                # We assume Column B for values and Column A for categories.
                                # Adjusting purely the row ranges.

                                # Value Reference (Column B)
                                new_val_ref = Reference(ws, min_col=2, min_row=start_row, max_row=end_row)
                                series.val.numRef.f = f"'{sheet_name}'!$B${start_row}:$B${end_row}"

                                # Category Reference (Column A)
                                if hasattr(series, 'cat') and hasattr(series.cat, 'strRef') and series.cat.strRef:
                                    series.cat.strRef.f = f"'{sheet_name}'!$A${start_row}:$A${end_row}"
                                elif hasattr(series, 'cat') and hasattr(series.cat, 'numRef') and series.cat.numRef:
                                    series.cat.numRef.f = f"'{sheet_name}'!$A${start_row}:$A${end_row}"

                                print(f"  Updated Chart {i+1}, Series {j+1} references to rows {start_row}-{end_row}.")
                                updated_any = True
                            except Exception as e:
                                print(f"  Could not update Chart {i+1}, Series {j+1}: {e}")
                else:
                    print(f"Sheet '{sheet_name}': No charts found to update.")
            else:
                print(f"Sheet '{sheet_name}': Could not find rows for '{target_month}' in Column A.")
        else:
            print(f"Sheet '{sheet_name}' not found.")

    if updated_any:
        try:
            wb.save(file_path)
            print(f"Successfully saved updated Excel file to {file_path}")
        except Exception as e:
            print(f"Failed to save workbook: {e}")
    else:
        print("No charts were updated.")

if __name__ == '__main__':
    if len(sys.argv) < 3:
        print("Usage: python update_graphs.py <file_path> <target_month>")
        sys.exit(1)

    file_path = sys.argv[1]
    target_month = sys.argv[2]
    update_graphs(file_path, target_month)

