import zipfile
import re
import sys
import os
import shutil
import openpyxl
import datetime

def get_month_rows(ws, target_month_str):
    start_row = None
    end_row = None
    target_month_str = target_month_str.lower()
    for row in range(2, ws.max_row + 1):
        cell_val = ws.cell(row=row, column=1).value
        is_match = False
        if isinstance(cell_val, datetime.datetime):
            if cell_val.strftime('%b').lower() == target_month_str or cell_val.strftime('%B').lower() == target_month_str:
                is_match = True
        elif isinstance(cell_val, str):
            if target_month_str in cell_val.lower():
                is_match = True
        if is_match:
            if start_row is None:
                start_row = row
            end_row = row
    return start_row, end_row

def update_graphs_zip(input_file, output_file, target_month):
    print(f"Reading target rows for '{target_month}' from {input_file}...")
    try:
        wb = openpyxl.load_workbook(input_file, data_only=True)
    except Exception as e:
        print(f"Failed to open {input_file}: {e}")
        return

    sheets_of_interest = ['User_funnel', 'User Engagement', 'gameplay_report(score) ', 'gameplay_report(time) ']

    ranges = {}
    for sheet_name in sheets_of_interest:
        if sheet_name in wb.sheetnames:
            ws = wb[sheet_name]
            s, e = get_month_rows(ws, target_month)
            if s and e:
                ranges[sheet_name] = (s, e)
                print(f"Sheet '{sheet_name}': Found '{target_month}' data from row {s} to {e}.")
            else:
                print(f"Sheet '{sheet_name}': Could not find rows for '{target_month}' in Column A.")
    wb.close()

    if not ranges:
        print("No ranges found to update. Exiting.")
        return

    temp_dir = 'temp_excel_unzip'
    if os.path.exists(temp_dir):
        shutil.rmtree(temp_dir)

    print(f"Unzipping {input_file} to modify chart XML directly (preserves all unsupported objects)...")
    with zipfile.ZipFile(input_file, 'r') as zip_ref:
        zip_ref.extractall(temp_dir)

    charts_dir = os.path.join(temp_dir, 'xl', 'charts')
    updated_files = 0
    if os.path.exists(charts_dir):
        for filename in os.listdir(charts_dir):
            if filename.endswith('.xml'):
                filepath = os.path.join(charts_dir, filename)
                with open(filepath, 'r', encoding='utf-8') as f:
                    content = f.read()

                original_content = content

                def replace_formula(match):
                    tag = match.group(1)
                    full_ref = match.group(2)
                    if '!' in full_ref:
                        sheet_part, cell_part = full_ref.rsplit('!', 1)
                        sheet_name_clean = sheet_part.strip("'")

                        target_range = None
                        if sheet_name_clean in ranges:
                            target_range = ranges[sheet_name_clean]
                        else:
                            for k, v in ranges.items():
                                if k.strip() == sheet_name_clean.strip():
                                    target_range = v
                                    break

                        if target_range:
                            new_start, new_end = target_range
                            if ':' in cell_part:
                                left, right = cell_part.split(':')
                                left = re.sub(r'\d+', str(new_start), left)
                                right = re.sub(r'\d+', str(new_end), right)
                                new_cell_part = f"{left}:{right}"
                            else:
                                new_cell_part = re.sub(r'\d+', str(new_start), cell_part)
                            return f"<{tag}:f>{sheet_part}!{new_cell_part}</{tag}:f>"
                    return match.group(0)

                # Update the references
                content = re.sub(r'<(c|cx):f>(.*?)</\1:f>', replace_formula, content)

                # Remove caches so Excel evaluates the new formulas
                content = re.sub(r'<(c|cx):numCache>.*?</\1:numCache>', '', content, flags=re.DOTALL)
                content = re.sub(r'<(c|cx):strCache>.*?</\1:strCache>', '', content, flags=re.DOTALL)

                if content != original_content:
                    with open(filepath, 'w', encoding='utf-8') as f:
                        f.write(content)
                    print(f"Updated references in {filename}")
                    updated_files += 1

    if updated_files > 0:
        print(f"Zipping modified contents into {output_file}...")
        with zipfile.ZipFile(output_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(temp_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    arcname = os.path.relpath(file_path, temp_dir)
                    zipf.write(file_path, arcname)
        print(f"Successfully created {output_file}")
    else:
        print("No chart references matched the targeted sheets. No new file created.")

    shutil.rmtree(temp_dir)

if __name__ == '__main__':
    if len(sys.argv) < 3:
        print("Usage: python update_graphs.py <input_file> <target_month> [output_file]")
        sys.exit(1)

    input_file = sys.argv[1]
    target_month = sys.argv[2]

    if len(sys.argv) > 3:
        output_file = sys.argv[3]
    else:
        # Construct default output file name
        base, ext = os.path.splitext(input_file)
        output_file = f"{base}_{target_month}{ext}"

    update_graphs_zip(input_file, output_file, target_month)

